export const buildShRaw: string =
  '#!/usr/bin/env bash\nset -e\n\nCALM_MOC_PATH="/home/ubuntu/.motoko/moc/1.2.0/bin/moc"\nCALM_MOTOKO_CORE="/home/ubuntu/.motoko/core/moc-1.2.0"\n\n# Remove any prior src to avoid nested src/src\nBUILD_DIR=$(mktemp -d)\ncp -rf ./src/. "$BUILD_DIR/"\ncd "$BUILD_DIR"\n\nls -la\n\nif [ ! -x "$CALM_MOC_PATH" ]; then\n    echo "Error: Motoko compiler not found at $CALM_MOC_PATH" >&2\n    exit 1\nfi\n\nif [ ! -d "$CALM_MOTOKO_CORE" ]; then\n    echo "Error: Motoko core library not found at $CALM_MOTOKO_CORE" >&2\n    exit 1\nfi\n\npnpm install --prefer-offline --child-concurrency 2 --network-concurrency 6\npnpm --filter \'@caffeine/template-frontend\' build:skip-bindings\nnode scripts/prune-unused-images.js\nnode scripts/resize-images.js\n\n$CALM_MOC_PATH --implicit-package core --default-persistent-actors -no-check-ir -E M0236 -E M0235 -E M0223 -E M0237 --actor-idl src/backend/system-idl --package core "$CALM_MOTOKO_CORE" src/backend/main.mo -o src/backend/backend.wasm\n\nmkdir -p /workdir/src/frontend/\nmkdir -p /workdir/src/backend/\ncp -rf src/frontend/dist/ /workdir/src/frontend/ 2>/dev/null || echo "No frontend dist to copy"\ncp -f src/backend/backend.wasm /workdir/src/backend/ 2>/dev/null || echo "No backend wasm to copy"\n';

export const deployShRaw: string =
  "#!/bin/bash\nset -e \n# Usage: deploy.sh\n\n# Define cleanup function for exit\ncleanup() {\n    # Kill the icp-cli network process if it's running\n    icp network stop\n    exit $1\n}\n\n# Handle script interruption\ntrap 'cleanup 1' INT TERM\n\n\nicp network start -d\nicp canister create --environment local frontend\nicp canister create --environment local backend\nexport BACKEND_CANISTER_ID=$(icp canister settings show --environment local --id-only backend)\nexport STORAGE_GATEWAY_URL=http://localhost:6188\nexport II_URL=http://rdmx6-jaaaa-aaaaa-aaadq-cai.localhost:8000\n\nicp deploy --environment local frontend backend\n\n\necho \"Press Ctrl+C to stop the deployment and exit.\"\n# This loop keeps the script running until interrupted by Ctrl+C.\nwhile true; do\n    sleep 2\ndone";

