  '{\n  "templates": {\n    "declaration_generator": "0.1.0",\n    "build_template": "1.0.0"\n  },\n  "components": {\n    "core-infrastructure": "1.0.3",\n    "shadcn-ui": "1.0.0",\n    "build-template-react": "1.1.0",\n    "initial-app": "1.0.0",\n    "github-export-icp-cli": "1.0.1"\n  },\n  "tags": [],\n  "aiCoreVersion": "0.dev"\n}';

export const pruneUnusedImagesRaw: string =
  'import { promises as fs } from "fs";\nimport path from "path";\n\nconst DIST_ASSETS_DIR = "src/frontend/dist/assets";\nconst GENERATED_DIR = path.join(DIST_ASSETS_DIR, "generated");\n\nconst IMAGE_EXTENSIONS = new Set([\n  ".jpg",\n  ".jpeg",\n  ".png",\n  ".webp",\n  ".gif",\n  ".svg",\n  ".ico",\n  ".avif",\n]);\n\nasync function fileExists(filePath) {\n  try {\n    await fs.access(filePath);\n    return true;\n  } catch {\n    return false;\n  }\n}\n\nasync function getAssetFiles(dir) {\n  const files = [];\n\n  try {\n    const entries = await fs.readdir(dir, { withFileTypes: true });\n\n    for (const entry of entries) {\n      const fullPath = path.join(dir, entry.name);\n\n      if (entry.isDirectory()) {\n        // Skip the generated folder itself\n        if (entry.name !== "generated") {\n          files.push(...(await getAssetFiles(fullPath)));\n        }\n      } else if (\n        entry.name.endsWith(".js") ||\n        entry.name.endsWith(".mjs") ||\n        entry.name.endsWith(".css")\n      ) {\n        files.push(fullPath);\n      }\n    }\n  } catch (error) {\n    console.error(`Error reading directory ${dir}:`, error.message);\n  }\n\n  return files;\n}\n\nasync function getImagesInDir(dir) {\n  const images = [];\n\n  try {\n    const entries = await fs.readdir(dir, { withFileTypes: true });\n\n    for (const entry of entries) {\n      if (entry.isFile()) {\n        const ext = path.extname(entry.name).toLowerCase();\n        if (IMAGE_EXTENSIONS.has(ext)) {\n          images.push(entry.name);\n        }\n      }\n    }\n  } catch (error) {\n    if (error.code !== "ENOENT") {\n      console.error(`Error reading directory ${dir}:`, error.message);\n    }\n  }\n\n  return images;\n}\n\n\nasync function pruneImagesInDir(dir, label, combinedContent) {\n  const images = await getImagesInDir(dir);\n\n  if (images.length === 0) {\n    return { removedCount: 0, savedBytes: 0 };\n  }\n\n  console.log(`Found ${images.length} image(s) in ${label} folder`);\n\n  const referencedImages = new Set();\n  for (const filename of images) {\n    if (combinedContent.includes(filename)) {\n      referencedImages.add(filename);\n    }\n  }\n\n  console.log(\n    `Found ${referencedImages.size} ${label} image reference(s) in compiled assets`,\n  );\n\n  const unusedImages = images.filter((img) => !referencedImages.has(img));\n\n  if (unusedImages.length === 0) {\n    console.log(`No unused ${label} images to prune`);\n    return { removedCount: 0, savedBytes: 0 };\n  }\n\n  let removedCount = 0;\n  let savedBytes = 0;\n\n  const BATCH_SIZE = 10;\n  for (let i = 0; i < unusedImages.length; i += BATCH_SIZE) {\n    const batch = unusedImages.slice(i, i + BATCH_SIZE);\n\n    const results = await Promise.all(\n      batch.map(async (image) => {\n        const imagePath = path.join(dir, image);\n        try {\n          const stats = await fs.stat(imagePath);\n          await fs.unlink(imagePath);\n          return { success: true, image, size: stats.size };\n        } catch (error) {\n          return { success: false, image, error: error.message };\n        }\n      }),\n    );\n\n    for (const result of results) {\n      if (result.success) {\n        removedCount++;\n        savedBytes += result.size;\n        console.log(`  Removed: ${result.image} (${formatBytes(result.size)})`);\n      } else {\n        console.error(`  Failed to remove ${result.image}: ${result.error}`);\n      }\n    }\n  }\n\n  return { removedCount, savedBytes };\n}\n\nasync function pruneUnusedImages() {\n  if (!(await fileExists(DIST_ASSETS_DIR))) {\n    console.log(`Directory ${DIST_ASSETS_DIR} does not exist, skipping prune`);\n    return;\n  }\n\n  const assetFiles = await getAssetFiles(DIST_ASSETS_DIR);\n\n  if (assetFiles.length === 0) {\n    console.log("No JS/CSS files found in dist/assets, skipping prune");\n    return;\n  }\n\n  const jsCount = assetFiles.filter(\n    (f) => f.endsWith(".js") || f.endsWith(".mjs"),\n  ).length;\n  const cssCount = assetFiles.filter((f) => f.endsWith(".css")).length;\n  console.log(\n    `Scanning ${jsCount} JS file(s) and ${cssCount} CSS file(s) for image references...`,\n  );\n\n  // Read all JS/CSS content once, reuse for both directories\n  const contents = await Promise.all(\n    assetFiles.map((file) => fs.readFile(file, "utf-8").catch(() => "")),\n  );\n  const combinedContent = contents.join("\\n");\n\n  const generated = await pruneImagesInDir(\n    GENERATED_DIR,\n    "generated",\n    combinedContent,\n  );\n  const uploaded = await pruneImagesInDir(\n    DIST_ASSETS_DIR,\n    "uploaded",\n    combinedContent,\n  );\n\n  const totalRemoved = generated.removedCount + uploaded.removedCount;\n  const totalSaved = generated.savedBytes + uploaded.savedBytes;\n\n  if (totalRemoved > 0) {\n    console.log(\n      `\\nPruned ${totalRemoved} unused image(s) total, saved ${formatBytes(totalSaved)}`,\n    );\n  } else {\n    console.log("\\nNo unused images to prune");\n  }\n}\n\nfunction formatBytes(bytes) {\n  if (bytes === 0) return "0 B";\n  const k = 1024;\n  const sizes = ["B", "KB", "MB", "GB"];\n  const i = Math.floor(Math.log(bytes) / Math.log(k));\n  return `${(bytes / Math.pow(k, i)).toFixed(1)} ${sizes[i]}`;\n}\n\npruneUnusedImages().catch((error) => {\n  console.error("Image prune process failed:", error);\n  process.exit(1);\n});\n';

export const resizeImagesRaw: string =
  'import sharp from "sharp";\nimport { promises as fs } from "fs";\nimport path from "path";\n\nconst DIMENSION_PATTERN = /^(.+?)\\.dim_(\\d+)x(\\d+)(\\.[^.]+)$/;\nconst DIST_ASSETS_DIR = "src/frontend/dist/assets";\nconst GENERATED_DIR = path.join(DIST_ASSETS_DIR, "generated");\nconst IMAGE_DIRS = [GENERATED_DIR, DIST_ASSETS_DIR];\n\nasync function fileExists(filePath) {\n  try {\n    await fs.access(filePath);\n    return true;\n  } catch {\n    return false;\n  }\n}\n\nfunction getOutputOptions(ext) {\n  const extension = ext.toLowerCase();\n\n  switch (extension) {\n    case ".png":\n      return {\n        format: "png",\n        options: {\n          compressionLevel: 6, // (0-9) 6 for balance of speed and size\n          palette: true, // Quantize to 256 colors\n          quality: 80, // Quality for palette quantization\n          effort: 8, // (0-10)\n          adaptiveFiltering: true,\n        },\n      };\n    case ".jpg":\n    case ".jpeg":\n      return {\n        format: "jpeg",\n        options: {\n          quality: 80, // 80 is a good balance\n          mozjpeg: true, // Use MozJPEG encoder (much better compression)\n          trellisQuantisation: true,\n          overshootDeringing: true,\n          optimizeScans: true,\n        },\n      };\n    case ".webp":\n      return {\n        format: "webp",\n        options: {\n          quality: 80,\n          effort: 6, // Max effort (0-6)\n          smartSubsample: true,\n        },\n      };\n    default:\n      return null;\n  }\n}\n\nasync function resizeImagesInDir(dir) {\n  if (!(await fileExists(dir))) {\n    return 0;\n  }\n\n  let files;\n  try {\n    files = await fs.readdir(dir);\n  } catch (error) {\n    console.log(`Could not read ${dir}: ${error.message}`);\n    return 0;\n  }\n\n  let resizedCount = 0;\n\n  for (const file of files) {\n    const match = file.match(DIMENSION_PATTERN);\n    if (match) {\n      const [, , width, height, ext] = match;\n      const filePath = path.join(dir, file);\n      const outputConfig = getOutputOptions(ext);\n\n      if (!outputConfig) {\n        console.log(`Skipping unsupported format: ${file}`);\n        continue;\n      }\n\n      try {\n        let pipeline = sharp(filePath)\n          .resize(parseInt(width, 10), parseInt(height, 10), {\n            fit: "cover",\n            withoutEnlargement: false,\n            position: "center",\n          })\n          .keepIccProfile();\n\n        // Apply format-specific optimization\n        pipeline = pipeline[outputConfig.format](outputConfig.options);\n\n        const resized = await pipeline.toBuffer();\n        await fs.writeFile(filePath, resized);\n        resizedCount++;\n      } catch (error) {\n        console.error(`Failed to resize ${file}:`, error.message);\n      }\n    }\n  }\n\n  return resizedCount;\n}\n\nasync function resizeImages() {\n  let totalResized = 0;\n\n  for (const dir of IMAGE_DIRS) {\n    const count = await resizeImagesInDir(dir);\n    if (count > 0) {\n      console.log(`Resized ${count} image(s) in ${dir}`);\n    }\n    totalResized += count;\n  }\n\n  if (totalResized > 0) {\n    console.log(`Resized ${totalResized} image(s) total`);\n  } else {\n    console.log("No images to resize");\n  }\n}\n\nresizeImages().catch((error) => {\n  console.error("Image resize process failed:", error);\n  process.exit(1);\n});\n';

